def transition(state, action):
    s = dict(state)
    slots = dict(s.get("slots", {}))
    name = action.get("name")
    params = action.get("params", {}) or {}

    s["turns"] = s.get("turns", 0) + 1
    s["last_action"] = name

    def all_filled():
        return bool(slots) and all(v is not None for v in slots.values())

    # `done` is terminal: only the turn counter advances.
    if s.get("status") == "done":
        s["slots"] = slots
        s["filled_count"] = sum(1 for v in slots.values() if v is not None)
        return s

    if name == "ask":
        # Ask about the named slot, or fall back to the first still-empty slot.
        slot = params.get("slot")
        if slot is None:
            for k in slots:
                if slots[k] is None:
                    slot = k
                    break
        if slot is not None and slot in slots and slots[slot] is None:
            s["pending"] = slot

    elif name == "fill_slot":
        # The value lands in the named slot, or the one we're waiting on.
        slot = params.get("slot")
        if slot is None:
            slot = s.get("pending")
        value = params.get("value")
        if slot is not None and slot in slots and value is not None:
            slots[slot] = value
            if s.get("pending") == slot:
                s["pending"] = None
            # The form changed, so any earlier confirmation no longer holds.
            s["confirmed"] = False
            s["status"] = "collecting"

    elif name == "confirm":
        # Confirmation is only meaningful once the whole form is filled.
        if all_filled():
            s["confirmed"] = True
            s["status"] = "confirming"
            s["pending"] = None

    elif name == "complete":
        # Finalize only a fully filled, confirmed form.
        if all_filled() and s.get("confirmed"):
            s["status"] = "done"
            s["pending"] = None

    s["slots"] = slots
    s["filled_count"] = sum(1 for v in slots.values() if v is not None)
    return s

