def perceive(data):
    text = data if isinstance(data, str) else str(data.get("text", ""))
    out = {"user_utterance": text}
    if ":" in text:
        slot, _, value = text.partition(":")
        slot = slot.strip().lower()
        value = value.strip()
        if slot:
            out["provided_slot"] = slot
        if value:
            out["provided_value"] = value
    return out
